<script setup lang="ts">
import{ref}from'vue'
import{useRouter}from'vue-router'
import{api}from'../api/client'
const router=useRouter(),form=ref({username:'',display_name:'',email:'',password:'',confirm:'',role:'student',student_usernames:''}),error=ref(''),success=ref(''),loading=ref(false)
async function submit(){error.value='';form.value.username=form.value.username.trim();form.value.display_name=form.value.display_name.trim();if(!/^[A-Za-z0-9_.-]{3,64}$/.test(form.value.username)){error.value='用户名需要 3～64 位，只能包含字母、数字、下划线、点或短横线';return}if(form.value.password.length<8){error.value='密码至少需要 8 位';return}if(form.value.password!==form.value.confirm){error.value='两次输入的密码不一致';return}const linked=form.value.student_usernames.split(/[,，\n]/).map(x=>x.trim()).filter(Boolean);if(form.value.role==='parent'&&!linked.length){error.value='家长账号必须填写至少一个已注册的学生用户名';return}loading.value=true;try{await api.post('/auth/register',{username:form.value.username,display_name:form.value.display_name,email:form.value.email.trim()||null,password:form.value.password,role:form.value.role,student_usernames:form.value.role==='parent'?linked:[]});success.value='注册成功，即将前往登录';setTimeout(()=>router.push('/login'),800)}catch(e:any){error.value=e.message}finally{loading.value=false}}
</script>
<template><div class="login card"><h1>注册账号</h1><p>请选择实际身份。家长账号必须绑定至少一个已注册学生。</p><form @submit.prevent="submit"><label>账号类型<select v-model="form.role"><option value="student">学生</option><option value="teacher">教师</option><option value="parent">家长</option></select></label><label>用户名<input v-model="form.username" required placeholder="字母、数字、下划线"></label><label>姓名<input v-model="form.display_name" required></label><label>邮箱（可选）<input type="email" v-model="form.email"></label><label v-if="form.role==='parent'">绑定学生用户名 <span class="field-help">多个学生用逗号或换行分隔</span><textarea v-model="form.student_usernames" required placeholder="student001, student002"></textarea></label><label>密码<input type="password" minlength="8" v-model="form.password" required></label><label>确认密码<input type="password" v-model="form.confirm" required></label><p class="error">{{error}}</p><p class="success">{{success}}</p><button :disabled="loading">{{loading?'注册中…':'注册'}}</button> <router-link to="/login">已有账号，返回登录</router-link></form></div></template>
